INSERT INTO `articles` (`id_article`, `titre`, `resume`, `id_categorie`, `contenu`, `image`, `date_creation`, `date_publication`, `date_modification`, `id_auteur`, `statut`, `nombre_lecture`, `type`, `pdf`) VALUES
(1, 'Cérémonie de rentrée solennelle des cours & tribunaux', 'Le bâtonnier Me Mamadou Seck a prononcé un discours lors de la rentrée des Co', 24, 'Le bâtonnier Me Mamadou Seck a prononcé un discours lors de la rentrée des Cours et tribunaux le 25 janvier 2024. Dans son discours, il a abordé plusieurs points importants, notamment :\r\n\r\n- Le financement de l\'assistance judiciaire: Le barreau a reçu une dotation annuelle de 600 millions de francs CFA en 2020 pour l\'assistance judiciaire, mais les règlements ne sont pas réguliers. Les dotations pour les années 2021, 2022 et 2023 n\'ont pas encore été reçues.\r\n- La création d\'une école d\'avocats: Le barreau a besoin de moyens financiers complémentaires pour créer une école d\'avocats qui permettra de former 100 jeunes dans la première année. Le bâtonnier a également salué les efforts du président de la République pour mettre à la disposition du barreau un terrain d\'un hectare et une aide financière de 500 millions de francs CFA.\r\n- Les attaques contre l\'institution judiciaire: Il a également souligné que l\'institution judiciaire a résisté aux critiques et aux attaques dont elle a fait l\'objet ces derniers temps.\r\n- La confiance des justiciables: Le bâtonnier a reconnu que la confiance des justiciables est éprouvée. Il a appelé à une pédagogie et à une conscience de la responsabilité pour regagner cette confiance.\r\n- Les menaces aux libertés: Le bâtonnier a souligné que des forces s\'élèvent chaque jour pour briser les libertés. Il a appelé les avocats à résister à ces forces et à défendre les valeurs de la République.\r\n\r\nLe discours du bâtonnier Me Mamadou Seck est un plaidoyer pour une justice forte et indépendante. Il a appelé les autorités à mettre à la disposition du barreau les moyens nécessaires pour qu\'il puisse remplir sa mission. Il a également appelé les avocats à être vigilants et à défendre les libertés.', 'images_articles/Juridique/rentree.jpg', '2025-01-30', '2025-01-30', NULL, 1, '1', 18, 'text', NULL),
(2, 'Communiqué du conseil de l\'ordre', '\" Le Barreau du Sénégal suit avec une attention particulière l\'évolution pr', 24, '\" Le Barreau du Sénégal suit avec une attention particulière l\'évolution préoccupante de la situation politique et institutionnelle qui prévaut dans notre pays suite aux décisions prises par les plus hautes institutions de la République notamment :\r\n\r\n- la décision du Conseil Constitutionnel sur la désignation des candidats à la présidentielle de 2024\r\n\r\n- la mise en place d’une commission d’enquête parlementaire sur d’éventuels faits de corruption de membres du Conseil Constitutionnel\r\n\r\n- l’abrogation par le Président de la République du décret portant convocation du corps électoral\r\n\r\n- la décision de l’Assemblée Nationale de fixer la date des élections au 15 décembre 2024\r\n\r\nEn l’absence d’éléments factuels d’appréciation et d’analyse, le Barreau relève que les faits imputés, au même titre que les décisions prises, sont graves et porteurs d’incertitudes pour le Sénégal.\r\nCette situation, quels qu’en puissent être les motivations et les sièges de responsabilités, met en péril la stabilité du pays, la paix sociale et le respect des institutions garantes de notre démocratie et de la République. Soucieux de la préservation des valeurs de l’Etat de droit et rigoureusement attaché aux principes de légalité, le Barreau du Sénégal proscrit toute atteinte à l’ordre constitutionnel qui viole les principes démocratiques et pourrait installer le pays dans un cycle de violence et d’insécurité majeures.\r\n\r\nLe Barreau du Sénégal condamne vigoureusement toute violence dans l’espace social, déplore les dégâts matériels ainsi que les pertes en vies humaines et présente ses condoléances aux familles endeuillées.\r\nTout en appelant à la retenue et à l’apaisement des populations, notamment des jeunes, il en appelle aux pouvoirs publics afin de traiter l’appel, il exige que les institutions, dans leur rôle respectif, instruisent des auteurs d’abus ou de forfaits des sanctions sévères et exemplaires. La liberté de candidature garantie par la Constitution ainsi que l’exigence du respect de l’ordre public ne doivent absolument pas justifier ou légitimer la violence.\r\n\r\ncomme mode d’expression ou de répression des revendications dans un Etat de droit.\r\nLors de la rentrée des cours et tribunaux le 25 janvier 2024, le Barreau rappelait au Président de la République, aux acteurs de la justice et ceux politiques, l’exigence du respect du serment, de l’attitude républicaine et le courage d’assumer le poids du sacrifice individuel au service de la nation, pour qu’ils aient toujours à l’esprit que les hommes passent et que les institutions demeurent. Le constat intangible dans la situation que nous vivons actuellement est que le citoyen, le peuple, n’est qu’une variable d’ajustement pour les acteurs politiques qui rusent avec les principes du vivre en commun.\r\nLes intérêts du peuple sénégalais ne peuvent se mesurer à l’aune des objectifs et attentes politiques ou des défaillances dans l’application de la règle de droit. Le Barreau du Sénégal appelle au respect scrupuleux de la loi fondamentale et des droits qu’elle consacre au citoyen.\r\n\r\nIl rappelle qu’il ne suffira pas d’ouvrir des concertations entre seuls acteurs de la classe politique ni de trouver des solutions ponctuelles à des questions structurelles profondes.\r\nIl s’agira surtout, pour préserver les fondements de l’Etat de droit, de remettre le citoyen et la République au centre des préoccupations afin de trouver autour de l’intérêt supérieur de la nation les raisons de taire les divergences partisanes et de rendre compatibles les ambitions proclamées pour le peuple sénégalais. Notre pays a une longue tradition de légalité et son peuple a toujours su se retrouver autour des valeurs et principes qui fondent, par-delà nos différences et nos adversités, notre commun vouloir de vie commune.\r\nUne nouvelle fois, le jeu et les enjeux politiques convoquent les organisations et les institutions républicaines de notre pays mais aussi et surtout le peuple profond, silencieux et majoritaire à démontrer leur capacité à appréhender cette crise et à en sortir le peuple sénégalais, indemne et uni. Pour restaurer la confiance nécessaire du citoyen dans nos lois, redorer les blasons ternis de nos institutions et surtout préserver la paix et la stabilité du Sénégal.\r\nDakar, le 14 février 2024\r\nPour le Conseil de l’Ordre\r\nLe Secrétaire Général\r\nMaître Ibrahima NDIEGUENE \"', 'images_articles/Juridique/communique_report_presidentielle.jpg', '2025-01-30', '2025-01-30', NULL, 1, '1', 8, 'text', NULL),
(3, 'Signature du bail afférent au terrain d’un hectare destiné à l’édification de l’Ecole des Avocats du Sénégal', 'Le mardi 1er Mars 2022 à 17 h, dans les locaux de la DGPU, M. le Bâtonnier Pap', 24, 'Le mardi 1er Mars 2022 à 17 h, dans les locaux de la DGPU, M. le Bâtonnier Papa Laïty Ndiaye (prédécesseur de Me Mamadou Seck), conjointement avec M. le Ministre Diène Farba Sarr, Délégué Général au Pôle Urbain de Diamniadio, assisté de ses collaborateurs, signé le bail afférent au terrain d’un hectare destiné à l’édification de l’Ecole des Avocats du Sénégal.\r\nLe Bâtonnier était accompagné de Me Mamadou Seck, Dauphin, Me Ibrahima Ndiéguéne Secrétaire Général, Me Samba Bitèye Trésorier Général, Me Ousmane Thiam Secrétaire Général Adjoint et de M. Ibrahima Diack, Secrétaire exécutif.\r\nLe terrain d’un hectare avait déjà été identifié et visité le 23 juin 2021 par une délégation de l’Ordre .\r\n\r\nLa signature du bail sera suivie dans les prochaines semaines de la désignation par l’Agetip ( MOD) de l’entreprise chargée de la construction et de la pose de la première pierre de cette école qui constitue un maillon très important du dispositif de formation des avocats.', 'images_articles/Juridique/signature_bail.jpg', '2025-01-30', '2025-01-30', NULL, 1, '1', 2, 'text', NULL);
