INSERT INTO `documentheques` (`id`, `code_type`, `titre`, `description`, `lien`) VALUES
(1, '201', 'Code de déontologie des avocats de l’espace UEMOA', 'Ce document présente les règles déontologiques régissant la profession d\'avocat dans l\'espace UEMOA, assurant l\'indépendance, la probité et la qualité des services juridiques.', 'documentheques/201/201_1738671726362.pdf'),
(2, '201', 'Règlement d’exécution n° 001 2018 com UEMOA relatif au droit de plaidoirie', 'Ce document décrit les règles de paiement du droit de plaidoirie pour les avocats de l\'UEMOA, incluant les montants, les modalités, et les conséquences en cas de non-paiement.', 'documentheques/201/201_1738671790979.pdf'),
(3, '201', 'Règlement d’exécution n° 001 2019 com uemoa relatif au CAPA', 'Ce document détaille les modalités d\'obtention du Certificat d\'Aptitude à la Profession d\'Avocat dans l\'espace UEMOA, favorisant la mobilité et la compétitivité des Avocats au sein de l\'Union.', 'documentheques/201/201_1738671821696.pdf'),
(4, '201', 'Règlement d’exécution n° 002 2019 com uemoa relatif à la formation des avocats', 'Ce document présente les obligations de formation initiale et continue des avocats inscrits dans un Barreau de l\'UEMOA pour renforcer leurs compétences et garantir l\'excellence professionnelle.', 'documentheques/201/201_1738671851507.pdf'),
(5, '201', 'Règlement d’exécution n° 003 2018 com uemoa relatif à l’acte d’avocat', 'Ce document présente le Règlement d\'exécution relatif à l\'acte d\'avocat dans l\'espace UEMOA, détaillant les obligations des avocats, les modalités d\'enregistrement et de conservation des actes, ainsi que les sanctions en cas de non-respect des règles professionnelles.', 'documentheques/201/201_1738671886631.pdf'),
(6, '201', 'Règlement d’exécution n° 002 2018 com uemoa relatif à la CARPA', 'Ce document présente le Règlement d\'exécution relatif à la Caisse Autonome de Règlements Pécuniaires des Avocats (CARPA) dans l\'espace UEMOA, détaillant les modalités de gestion des fonds des clients, l\'administration de la CARPA, et les règles de maniement des fonds par les avocats.', 'documentheques/201/201_1738671916831.pdf'),
(7, '201', 'Règlement n° 05 2014 cm uemoa relatif à l\'harmonisation des règles régissant la profession', 'Ce document présente les règlements d\'exécution concernant la Caisse Autonome de Règlements Pécuniaires des Avocats dans l\'espace UEMOA, incluant les obligations, les modalités de gestion des fonds, et les sanctions en cas de non-respect.', 'documentheques/201/201_1738671952149.pdf'),
(9, '202', 'Acte uniforme portant organisation des procédures simplifiées de recouvrement et des voies d\'exécution', 'Le présent acte uniforme s\'applique aux procédures d\'injonction de payer et d\'injonction d.e délivrer ou de restituer, aux saisies conservatoires et aux voies d\'exécution', 'documentheques/202/202_1738671285010.pdf'),
(10, '202', 'A.U révisé relatif au droit des sociétés commerciales et du groupement d\'intérêt économique', 'Aprés en avoir délibéré, le conseil des ministres adopte à l\'unamité des états parties présents et votant, L\'Acte uniforme dont la teneur suit', 'documentheques/202/202_1738671172418.pdf'),
(11, '202', 'Règlement d\'arbitrage de la cour commune de justice et d\'arbitrage', 'Les décisions que la cour en vue d\'assurer la mise en oeuvre et la bonne fin des procédures arbitrales et celles liées à l\'examen de la sentence, sont de nature administrative.', 'documentheques/202/202_1738671234808.pdf'),
(12, '202', 'Acte uniforme révisé portant sur le droit commercial général', 'Tout commerçant, personne physique ou morale y compris toutes sociétes commerciales dans lesquelles un état ou toute autre personne de droit public associé', 'AUDCG-2010_fr.pdf'),
(13, '202', 'Acte uniforme relatif au droit des sociétés coopératives', 'Toute société coopérative, toute union ou fédération de sociétés coopératives , dont le siège sociale est situé sur le territoire de l\'un des états parties au traité relatif à l\'harmonisation du droit des affaires en Afrique', 'documentheques/202/202_1738671356168.pdf'),
(14, '202', 'Acte uniforme révisé portant organisation des sûretés', 'Sauf disposition contraire du présent acte unifomre, tout débiteur dont la dette est née dans l\'exercice de sa profession ou se trouve en rapport direct avec l\'une de ses activités professionnelles, même si celle-ci n\'est pas principale', 'documentheques/202/202_1738671423315.pdf'),
(15, '202', 'A.U portant organisation des procédures collectives d\'apurement du passif', 'Le présent acte uniforme acte uniforme a pour objectif d\'organiser les procédures préventives de conciliation et de règlement préventif ainsi que les procédures curatives de redressement judiciaire', 'documentheques/202/202_1738671522825.pdf'),
(16, '202', 'A.U relatif au droit comptable et à l\'information financière', 'Toute entité au sens de l\'article 2 ci-dessous est soumise aux dispositions du présent Acte et doit mettre en place pour l\'information extrême et pour son propre usage , une comptabilité générale conformément audit Acte uniforme ', 'documentheques/202/202_1738671568190.pdf'),
(17, '202', 'Acte uniforme relatif à la médiation', 'Au sens du présent Acte uniforme le terme \"médiation\" désigne tout processus, quelle que soit son appellation, dans lequel les parties demandent à un tiers de les aider à parvenir à un règlement amiable d\'un litige, d\'un rapport conflictuel', 'documentheques/202/202_1738671603112.pdf'),
(18, '202', 'Règlement n°01/2014/CM/OHADA modifiant et complétant le règlement de procédure de la cour commune de justice', 'La cour commune de justice et d\'arbitrage est composé de neuf juges. Toutefois, le conseil des ministères, sur rapport circonstancioé et approfondi du secrétaire permanent', 'documentheques/202/202_1738671669945.pdf');
