INSERT INTO `types` (`id`, `code_type`, `titre`, `image`, `description`, `sous_titre`, `image_card`) VALUES
(1, '201', 'La Conférence des barreaux de l\'espace UEMOA', 'documentheques/201/uemoa2.jpg', 'L\'Union Économique et Monétaire Ouest Africaine (UEMOA) a été créée le 10 janvier 1994 à Dakar, au Sénégal. Cette institution sous-régionale regroupe huit États côtiers et sahéliens : le Bénin, le Burkina Faso, la Côte d’Ivoire, la Guinée-Bissau, le Mali, le Niger, le Sénégal et le Togo.\r\nCes pays partagent, entre autres, une monnaie commune, le Franc de la Communauté Financière Africaine (FCFA), dont l\'émission est confiée à la Banque Centrale des États de l\'Afrique de l\'Ouest (BCEAO).\r\nLa Conférence des Barreaux de l\'UEMOA (CB-UEMOA) joue un rôle essentiel dans la promotion et la défense des droits des avocats et de l\'État de droit dans les huit pays membres de l\'Union Economique et Monétaire Ouest Africaine (UEMOA).\r\nSes missions principales sont les suivantes:\r\n\r\n- Harmoniser les règles de la profession d\'avocat au sein de l\'espace UEMOA afin de garantir un traitement équitable des avocats et des justiciables.\r\n\r\n- Défendre les droits et intérêts des avocats en veillant au respect des principes de la liberté d\'exercice, d\'indépendance et de confraternelle.\r\nPromouvoir la formation continue des avocats pour leur permettre de mettre à jour leurs connaissances et compétences juridiques.\r\n\r\n- Contribuer à la promotion de l\'État de droit et des droits humains dans l\'espace UEMOA en sensibilisant les citoyens sur leurs droits et libertés.\r\n', 'Conférence des barreaux', 'documentheques/201/201_1738670805271.png'),
(2, '202', 'L\'OHADA', 'documentheques/202/ohada2.jpg', 'L\'Organisation pour l\'Harmonisation en Afrique du Droit des Affaires (OHADA) joue un rôle crucial dans l\'harmonisation du droit des affaires en Afrique.\r\nElle vise à:\r\n\r\n- Promouvoir la sécurité juridique et judiciaire pour les investisseurs et les entreprises.\r\n\r\n- Encourager la création d\'entreprises et l\'attrait des investissements.\r\n\r\n- Favoriser le développement économique et la création d\'un vaste marché intégré.\r\n\r\nL\'OHADA adopte des textes uniformes appelés Actes uniformes qui sont applicables dans tous ses États membres. Ces Actes uniformes couvrent un large éventail de domaines du droit des affaires, tels que le droit des sociétés commerciales, le droit des sûretés, le droit des procédures collectives et le droit de l\'arbitrage.', 'L\'espace OHADA', 'documentheques/202/202_1738670789813.png'),
(3, '200', 'Les textes régissant l\'OAS', 'documentheques/200/textesordre.jpg', ' ', 'Textes régissant le barreau du sénégal', 'documentheques/200/200_1738670900454.png');
